import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r as i,o as c,c as p,f as d,a as s,b as a,d as o,e}from"./app-76dad89e.js";const t={},r=s("blockquote",null,[s("p",null,[a("由于在 "),s("code",null,"Windows"),a(" 下开WSL和IDE导致电脑内存已经吃不消了，所以我直接把电脑系统刷成了 "),s("code",null,"Linux"),a(" （彻底疯狂了），这里记录一下我的配置过程")])],-1),h=e('<div class="hint-container tip"><p class="hint-container-title">提示</p><p>2023.10 更新微信安装及其配置， wps安装及其配置， 美化主题配置 请看<a href="#%E6%9B%B4%E6%96%B0">更新</a></p></div><p>放一张图展示一下我的成果</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/MyDesktop-2023-05-12.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><blockquote><p>桌面是我最爱的拿不拿术曲！</p></blockquote><h1 id="电脑配置" tabindex="-1"><a class="header-anchor" href="#电脑配置" aria-hidden="true">#</a> 电脑配置</h1><p><code>Honor Magicbook 14 2023</code></p><p>价格：4999</p><h1 id="踩坑经历" tabindex="-1"><a class="header-anchor" href="#踩坑经历" aria-hidden="true">#</a> 踩坑经历</h1><p>安装 <code>Manjaro</code> 前还试了另外几个发行版：</p><ol><li><p><code>Arch Linux</code></p></li><li><p><code>Deepin V23 Alpha</code></p></li></ol><p><code>Ubuntu</code> 就不算了，已经用懒了，完全不想折腾 <code>Debian</code> 系的东西了= =</p><p>对于 <code>Arch Linux</code>，我的安装步骤都没有任何问题，但是在登录本机的 <code>root</code> 帐号时，会出现终端一直输入 <code>^@</code> 这个符号的情况，导致我无法登录，所以这个就直接寄了</p><p>对于 <code>Deepin</code>，安装是没啥问题，特别顺利，完全是傻瓜式安装，然而它实在是太卡了，桌面动画卡成 <code>PPT</code> 的样子，和上古时代 <code>C</code> 盘被占满的 <code>Win 7</code> 一样</p><p>所以到后来就直接选择基于 <code>Arch</code> 的 <code>Manjaro</code></p><h1 id="安装" tabindex="-1"><a class="header-anchor" href="#安装" aria-hidden="true">#</a> 安装</h1><p>这里我只针对我的电脑进行讲解，因为是刚出的电脑，所以 <code>Linux</code> 在驱动支持上做的比较差，如果要装 <code>Linux</code> 的话，那就需要放弃一些功能，包括但不限于：</p><ol><li><p>指纹解锁</p></li><li><p>荣耀官方的电池管理系统 <code>OS Turbo 2.0</code></p></li><li><p>键盘莫名其妙一直输入 <code>^@</code></p></li><li><p>屏幕亮度会被莫名其妙的调节 （已解决）</p></li></ol><p>可能还有很多坑我还没踩到……</p><h2 id="制作-u-启" tabindex="-1"><a class="header-anchor" href="#制作-u-启" aria-hidden="true">#</a> 制作 <code>U</code> 启</h2><blockquote><p>注意这一步都是在 <code>Windows</code> 系统下完成的</p></blockquote>',20),y={href:"https://manjaro.org/download/",target:"_blank",rel:"noopener noreferrer"},m=e(`<p>选择 <code>PLASMA DESKTOP</code> （会好看一些？个人感觉），选择 <code>Minimal</code> 下载</p><p>下载之后，使用刻录工具，例如我使用的 <code>Rufus</code> 将此 iso 文件刻录到 <code>u</code> 盘中，成为一个 <code>u</code> 启 （注意选择分区模式为 <code>GPT</code> 而非 <code>MBR</code>）</p><h1 id="安装系统" tabindex="-1"><a class="header-anchor" href="#安装系统" aria-hidden="true">#</a> 安装系统</h1><p>插入 U 盘，开机，疯狂按 <code>F12</code> 进入 <code>BIOS</code> ，在这里设置几样内容：</p><ol><li><p>语言设置为简体中文</p></li><li><p>将启动顺序通过 <code>F5, F6</code> 调整顺序，将 <code>USB</code> 放在最上面</p></li><li><p>关闭 <code>安全模式</code>，否则将无法启动</p></li><li><p>将指纹解锁功能关闭</p></li></ol><p>最后按 <code>F10</code> 即可保存退出，然后就会进入 <code>Manjaro</code> 的引导页面，进入后跟着安装向导一步一步来即可（甚至都不用自己分区，完全是傻瓜式装机）</p><h1 id="配置系统" tabindex="-1"><a class="header-anchor" href="#配置系统" aria-hidden="true">#</a> 配置系统</h1><p>安装结束后，就可以顺利进入系统了，第一次进入系统一般会弹出这样的提示框：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/2023-05-12_01-15.png" alt="2023-05-12_01-15.png" tabindex="0" loading="lazy"><figcaption>2023-05-12_01-15.png</figcaption></figure><p>(可能右下角的语言会是英文，但没关系，可以设置为中文)</p><p>在这里点击 <code>Application</code> 必须要选的内容如下：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/2023-05-12_01-21.png" alt="2023-05-12_01-21.png" tabindex="0" loading="lazy"><figcaption>2023-05-12_01-21.png</figcaption></figure><p>这样会省去一些配置的时间（比如烦人的中文输入法），然后点击 <code>UPDATE SYSTEM</code> 即可</p><p>接下来是 <code>AUR</code> 的安装（这也是为什么要使用 <code>Arch</code> 系的原因）</p><p>但在安装之前，我们需要更新一下镜像源：</p><p>打开 <code>Konsole</code>，运行命令：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pacman-mirrors</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-i</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-c</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">China</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-m</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">rank</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>然后选择前三个镜像源即可，不用全选上（似乎全选上会有负面影响）</p><p>然后运行</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pacman</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-Syyu</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>更新即可（记住这个命令，以后每天早上开机后都要滚一滚）</p><p>然后我们就可以开始配置 <code>AUR</code> 了，这里我们选择 <code>yay</code></p><p>首先我们下载 <code>git</code> 和 <code>base-devel</code></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pacman</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">base-devel</span></span>
<span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pacman</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">git</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>随后：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#56B6C2;">cd</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">/opt</span></span>
<span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">git</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">clone</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">https://aur.archlinux.org/yay</span></span>
<span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">chown</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-R</span><span style="color:#ABB2BF;"> &lt;</span><span style="color:#98C379;">usernam</span><span style="color:#ABB2BF;">e&gt;</span><span style="color:#98C379;">:users</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">./yay</span></span>
<span class="line"><span style="color:#56B6C2;">cd</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">yay/</span></span>
<span class="line"><span style="color:#E06C75;">GOPROXY</span><span style="color:#56B6C2;">=</span><span style="color:#98C379;">https://goproxy.cn</span><span style="color:#ABB2BF;"> </span><span style="color:#61AFEF;">makepkg</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-si</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>请将 <code>&lt;username&gt;</code> 替换为你的用户名</p><p>等待安装结束即可，此后我们安装包只需要：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">xxxx</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>即可安装（更新其实也可以用 <code>yay</code>）</p><h2 id="常用软件安装" tabindex="-1"><a class="header-anchor" href="#常用软件安装" aria-hidden="true">#</a> 常用软件安装</h2><h3 id="工作类" tabindex="-1"><a class="header-anchor" href="#工作类" aria-hidden="true">#</a> 工作类</h3><ul class="task-list-container"><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-0" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-0"><code>OBS</code></label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-1" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-1"><code>QQ</code></label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-2" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-2"><code>WPS</code></label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-3" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-3"> 坚果云</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-4" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-4"> 谷歌浏览器</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-5" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-5"><code>v2ray</code> 与 <code>v2raya</code></label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-6" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-6"><code>Wechat</code></label></li></ul><p>给出每一样的安装步骤：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">obs-studio</span></span>
<span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">deepin-wine-qq</span></span>
<span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">wps-office</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">wps-office-mui-zh-cn</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">ttf-wps-fonts</span></span>
<span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">nutstore</span></span>
<span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">google-chrome</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>微信的安装其实也可以，但是在我这里会出现输入框的中文变成方框的问题，还没发现修改的方法，有佬知道怎么改的话请教教我（</p><p>对于 <code>v2ray</code> ，安装过程也比较简单：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#ABB2BF;"> </span><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pacman</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">v2ray</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>安装 <code>v2ray</code> 内核，然后运行 <code>sudo systemctl enbale v2ray.service</code></p><p>随后安装 <code>v2raya</code></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">v2raya</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>即可</p><p>在浏览器中访问 <code>http://locahost:2017</code> 即可配置 <code>v2raya</code>（第一次登录需要配置帐号密码），后续对节点的设置与 <code>Windows</code> 下 <code>v2rayN</code> 的设置一致。</p><h3 id="开发类" tabindex="-1"><a class="header-anchor" href="#开发类" aria-hidden="true">#</a> 开发类</h3><ul class="task-list-container"><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-7" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-7"><code>JetBrains</code> 全家桶</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-8" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-8"><code>VS Code</code></label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-9" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-9"><code>Typora</code></label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-10" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-10"><code>Obsidian</code> ✅ 2023-10-05</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-11" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-11"><code>LunarVim</code></label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-12" disabled="disabled"><label class="task-list-item-label" for="task-item-12"><code>Emacs</code></label></li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">clion</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pycharm-professional</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">intellij-idea-ultimate-edition</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">goland</span></span>
<span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">typora</span></span>
<span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">obsidian</span></span>
<span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;">  </span><span style="color:#98C379;">visual-studio-code-bin</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>针对后面两种 <code>LunarVim</code> 和 <code>Emacs</code>，我觉得应该也没什么佬用，我在这里就不写了（</p><h3 id="游戏类" tabindex="-1"><a class="header-anchor" href="#游戏类" aria-hidden="true">#</a> 游戏类</h3><p>只下载了 <code>Steam</code>，但是这个需要用 <code>discover</code> 这个软件，所以还需要先</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">discover</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>然后还要装一个存储库：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pacman</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">flatpak</span></span>
<span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">flatpak</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">remote-add</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--if-not-exists</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">flathub</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">https://flathub.org/repo/flathub.flatpakrepo</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>完成后，就可以打开 <code>discover</code> ，然后在里面找到 <code>steam</code> 了</p><h1 id="桌面美化" tabindex="-1"><a class="header-anchor" href="#桌面美化" aria-hidden="true">#</a> 桌面美化</h1><h2 id="konsole-美化" tabindex="-1"><a class="header-anchor" href="#konsole-美化" aria-hidden="true">#</a> <code>Konsole</code> 美化</h2><h3 id="外观" tabindex="-1"><a class="header-anchor" href="#外观" aria-hidden="true">#</a> 外观</h3><ol><li><p>配色方案的新建与修改</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230512160505624.png" alt="image-20230512160505624" tabindex="0" loading="lazy"><figcaption>image-20230512160505624</figcaption></figure><p>这里我采用的 <code>shell</code> 为 <code>zsh</code>（也是 <code>Konsole</code> 默认的 <code>Shell</code> ）</p><p>在外观中，选择配色方案，这里我选择的为黑底白字，然后在右侧选择编辑：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230512160708622.png" alt="image-20230512160708622" tabindex="0" loading="lazy"><figcaption>image-20230512160708622</figcaption></figure><p>在编辑界面可以选择：</p><ol><li>背景图片</li><li>模糊背景</li><li>透明度</li></ol><p>等，按照自己喜好选择即可</p><p>字体推荐默认的 <code>Hack</code> 字体（感觉还挺好看的，如果想要选择其他字体的话，可以自己去 <code>AUR</code> 下载，然后在这里选择即可）</p></li></ol><h3 id="zsh-美化" tabindex="-1"><a class="header-anchor" href="#zsh-美化" aria-hidden="true">#</a> <code>zsh</code> 美化</h3><p>这里不用 <code>oh-my-zsh</code> 那些东西，只用原生的 <code>zsh</code> + <code>plugin</code></p><ol><li><p>首先删除 <code>～/.zshrc</code>， 然后重新打开 <code>zsh</code> 进行一些配置</p></li><li><p>安装插件</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pacman</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">zsh-autosuggestions</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">zsh-syntax-highlighting</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">zsh-theme-powerlevel10k</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">zsh-completions</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></li><li><p>启用插件，打开 <code>~/.zshrc</code>，加入以下代码</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#56B6C2;">source</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">/usr/share/zsh/plugins/zsh-syntax-highlighting/zsh-syntax-highlighting.zsh</span></span>
<span class="line"><span style="color:#56B6C2;">source</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">/usr/share/zsh/plugins/zsh-autosuggestions/zsh-autosuggestions.zsh</span></span>
<span class="line"><span style="color:#56B6C2;">source</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">/usr/share/zsh-theme-powerlevel10k/powerlevel10k.zsh-theme</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p>重启 <code>Konsole</code> ，即可进入 <code>powerlevel10k</code> 的配置界面，按照引导配置即可</p></li></ol><p>最终效果：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230512161304340.png" alt="image-20230512161304340" tabindex="0" loading="lazy"><figcaption>image-20230512161304340</figcaption></figure><h2 id="主题" tabindex="-1"><a class="header-anchor" href="#主题" aria-hidden="true">#</a> 主题</h2><p>直接给出我的配置，可以在 <code>KDE Store</code> 中下载（甚至都可以直接在 <code>AUR</code> 中下载）</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230512161437730.png" alt="image-20230512161437730" tabindex="0" loading="lazy"><figcaption>image-20230512161437730</figcaption></figure><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230512161450550.png" alt="image-20230512161450550" tabindex="0" loading="lazy"><figcaption>image-20230512161450550</figcaption></figure><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230512161503482.png" alt="image-20230512161503482" tabindex="0" loading="lazy"><figcaption>image-20230512161503482</figcaption></figure><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230512161519675.png" alt="image-20230512161519675" tabindex="0" loading="lazy"><figcaption>image-20230512161519675</figcaption></figure><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230512161540236.png" alt="image-20230512161540236" tabindex="0" loading="lazy"><figcaption>image-20230512161540236</figcaption></figure><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230512161557288.png" alt="image-20230512161557288" tabindex="0" loading="lazy"><figcaption>image-20230512161557288</figcaption></figure><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230512161610704.png" alt="image-20230512161610704" tabindex="0" loading="lazy"><figcaption>image-20230512161610704</figcaption></figure><h2 id="页面" tabindex="-1"><a class="header-anchor" href="#页面" aria-hidden="true">#</a> 页面</h2><p>用了一些有趣的插件</p><ol><li><code>Latte Dock</code></li><li><code>Panon</code></li><li><code>Awesome Widget</code></li></ol><p>大概就用了这三个，直接在 <code>AUR</code> 中安装的，安装之后 <code>Latte Dock</code> 需要用应用程序来启动，另外两个都是挂件类型，直接添加即可</p><p>具体的配置过程就不写了（因为感觉这个和审美关系比较大，我也没啥审美……）</p><h1 id="最后的最后" tabindex="-1"><a class="header-anchor" href="#最后的最后" aria-hidden="true">#</a> 最后的最后</h1><p>安装 <code>neofetch</code> 和 <code>lolcat</code> （必不可少</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pacman</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">neofetch</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">lolcat</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>然后就可以愉快的秀 <code>Terminal</code> 了</p><h1 id="更新" tabindex="-1"><a class="header-anchor" href="#更新" aria-hidden="true">#</a> 更新</h1><h2 id="wechat" tabindex="-1"><a class="header-anchor" href="#wechat" aria-hidden="true">#</a> Wechat</h2><p>在 <code>AUR</code> 官网上搜索 com.qq.weixin.deepin，然后yay下载即可</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">com.qq.weixin.deepin</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>会遇到的问题：</p><ol><li>输入框中大字只会出现方框不显示文字</li><li>缩放不对，显示的字体太小</li><li>输入法太小，看不清字</li></ol><p>前两个的解决方法都在网站上有，复制过来就是：</p><p>Q:高分屏缩放支持<br> A:执行 <code>WINEPREFIX=~/.deepinwine/Deepin-WeChat deepin-wine6-stable winecfg</code>，在显示标签下调整DPI,100%缩放为96dpi，依次类推200%缩放192dpi</p><p>Q:输入框无法显示输入字符，只显示口<br> A:可以下载安装宋体字体文件<code>simsun.ttc</code>，重启微信即可正常显示</p><blockquote><p>关于 Linux 如何安装字体，可以直接 Google</p></blockquote><p>关于输入法的问题：</p><p>可以用可视化界面解决，打开输入法的配置（一般输入法默认为 <code>Fcitx5</code>，在 <code>manjaro</code> 下可以直接用 <code>Manjaro-Hello</code> 来安装，不需要自己配置）：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/20231005161619.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>按照次序点击选择即可，字号选择自己看着舒服的就行。</p><h2 id="wps-配置" tabindex="-1"><a class="header-anchor" href="#wps-配置" aria-hidden="true">#</a> WPS 配置</h2><ol><li>显示配置</li><li>WPS Word无法导出pdf的配置</li></ol><p>显示的时候字号会变小，而且无法调整，我们在启动的社会加入参数即可。</p><p>选择一个 wps app，右键，点击 “编辑应用程序”，配置如下：</p><p><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/20231005161932.png" alt="image.png" loading="lazy"><br> 在环境变量处加上 <code>QT_FONT_DPI=xxx</code> 即可（xxx为你需要缩放的 DPI 值，一般为100, 120, 144）</p><p>WPS Word无法导出pdf：</p><p>此问题为缺少环境，其导出依赖于 <code>libtiff5.so.5</code>，下载安装即可：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">libtiff5</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="obsidian" tabindex="-1"><a class="header-anchor" href="#obsidian" aria-hidden="true">#</a> Obsidian</h2><p><code>Obsidian</code> 中还是存在很多问题的，但我觉得大部分都是插件之间冲突的原因，比如 <code>style setting</code> 和 <code>codeBlock customizer</code> 设置之后会导致很多插件的即时预览出现毛病……</p>`,104),g=s("code",null,"js",-1),u=s("code",null,"mesa",-1),b=s("code",null,"Manjaro",-1),B={href:"http://repo.archlinux.fr/",target:"_blank",rel:"noopener noreferrer"},k=s("br",null,null,-1),v=s("img",{src:"https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/20231005162845.png",alt:"image.png",loading:"lazy"},null,-1),A=e('<p>但论坛上给出了另外一种解决方法：</p><p><code>rm -rf .config/obsidian/GPUCache/</code></p><p>然后重启 <code>obsidian</code> 即可。</p><h2 id="美化" tabindex="-1"><a class="header-anchor" href="#美化" aria-hidden="true">#</a> 美化</h2><p>感觉是最无聊的一个板块（？</p><p>重新用的主题和一些配置如下：</p><p>主题：<code>Lavanda-Sea-Light</code><br> 应用程序风格：<code>kvantum</code><br> 视觉风格：<code>Lavanda-Sea-Dark</code><br> 窗口装饰元素：<code>Breezemite dark</code><br> 图标： <code>ePapirus</code><br> 光标：<code>Volantes Cursors</code><br> 欢迎界面：<code>Arch Simple Blue</code></p><p>目前界面如下：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/20231005163435.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure>',9);function F(f,x){const l=i("ExternalLinkIcon");return c(),p("div",null,[r,d("more"),h,s("p",null,[a("在官网上下载 iso 镜像： "),s("a",y,[a("https://manjaro.org/download/"),o(l)])]),m,s("p",null,[a("不过这里找的问题是查看关系图谱时直接黑了，什么图都没有，一般报错是报 "),g,a(" 的问题（甚至还是警告），据了解应该是 "),u,a(" 版本的问题，降版本可以解决（然而 "),b,a(" 清理了缓存之后就没办法降级了……能降级的"),s("a",B,[a("archlinuxfr"),o(l)]),a("直接停止维护了，如下："),k,v]),A])}const z=n(t,[["render",F],["__file","Manjaro-Linux.html.vue"]]);export{z as default};
